SELECT c.company_id, c.name, cu.update_description, cu.update_date
FROM companies c
LEFT JOIN company_updates cu ON c.company_id = cu.company_id AND cu.status = 'pending';

SELECT COUNT(DISTINCT companies.company_id)
FROM companies 
JOIN company_documents ON companies.company_id = company_documents.company_id;

SELECT users.user_name, users.email, company_documents.document_name, company_documents.document_file
FROM users
JOIN company_documents ON users.user_id = company_documents.uploaded_by;
